queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?scifimovies a :SciFi_Movies .
    ?scifimovies p:title ?title .
    ?scifimovies p:filmingLocation ?filminglocation_f .
    FILTER(STR(?filminglocation_f) = "New Zealand")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?fantasymovies a :FantasyMovies .
    ?fantasymovies p:title ?title .
    ?fantasymovies p:filmingLocation ?filminglocation_f .
    FILTER(STR(?filminglocation_f) = "New Zealand")
    BIND(?title AS ?o0)
  }
}

